ScriptGroup.Script:
mm = mm or {}
local function handle_window_command(which, action, a, b) which = which == "map" and "bigmap" or which if action == "show" then mm.minimap.set_window_visible(which, true) elseif action == "hide" then mm.minimap.set_window_visible(which, false) elseif action == "move" then mm.minimap.move_window(which, a, b) elseif action == "resize" then mm.minimap.resize_window(which, a, b) elseif action == "lock" then mm.minimap.lock_window(which, true) elseif action == "unlock" then mm.minimap.lock_window(which, false) end end
local function run_inspect(source) local ok, info = mm.import.inspect_sqlite(source) if not ok then mm.warn(info) return end
mm.note("inspect path: " .. tostring(info.path)) mm.note(string.format("inspect: compatible=%s, rooms=%d, exits=%d", tostring(info.compatible), info.room_count or 0, info.exit_count or 0)) if not info.compatible then mm.warn("Missing: " .. table.concat(info.missing or {}, ", ")) end end
mm.alias_specs = { {"^mapper help(?: (.*))?$", function(m) mm.show_help(m[2]) end}, {"^mapper goto (.+)$", function(m) local ok, err = mm.goto_room(m[2]); if not ok then mm.warn(err) end end}, {"^mapper walkto (.+)$", function(m) local ok, err = mm.walkto_room(m[2]); if not ok then mm.warn(err) end end}, {"^mapper resume$", function() local ok, err = mm.resume(); if not ok then mm.warn(err) end end}, {"^mapper stop$", function() send("stop") end}, {"^mapper thisroom$", function() mm.print_room_details() end}, {"^mapper showroom (.+)$", function(m) mm.print_room_details(m[2]) end}, {"^mapper quicklist(?: (on|off))?$", function(m) mm.state.quick_mode = mm.bool_arg(m[2], not mm.state.quick_mode); mm.note("quicklist " .. (mm.state.quick_mode and "on" or "off")) end}, {"^mapper shownotes(?: (on|off))?$", function(m) mm.state.shownotes = mm.bool_arg(m[2], not mm.state.shownotes); mm.note("shownotes " .. (mm.state.shownotes and "on" or "off")) end}, {"^mapper compact(?: (on|off))?$", function(m) mm.state.compact_mode = mm.bool_arg(m[2], not mm.state.compact_mode); mm.note("compact " .. (mm.state.compact_mode and "on" or "off")) end}, {"^mapper updown$", function() mm.state.show_up_down = not mm.state.show_up_down; mm.note("updown " .. (mm.state.show_up_down and "on" or "off")) end}, {"^mapper underlines?$", function() mm.state.underline_links = not mm.state.underline_links; mm.note("underlines " .. (mm.state.underline_links and "on" or "off")) end}, {"^mapper autolocate(?: (on|off))?$", function(m) mm.state.auto_locate = mm.bool_arg(m[2], not mm.state.auto_locate); mm.note("autolocate " .. (mm.state.auto_locate and "on" or "off")) end}, {"^mapper centerlocate(?: (on|off))?$", function(m) mm.state.center_on_locate = mm.bool_arg(m[2], not mm.state.center_on_locate); mm.note("centerlocate " .. (mm.state.center_on_locate and "on" or "off")) end}, {"^mapper locate$", function() send("look") end}, {"^mapper database$", function() mm.note("Current mapper database: " .. mm.state.map_db) end}, {"^mapper set database (.+)$", function(m) mm.state.map_db = m[2]; mm.note("Mapper database set to " .. m[2]) end}, {"^mapper native db$", function() mm.note("Native mapper DB: " .. tostring(mm.resolve_native_mapper_db(mm.state.native_mapper_db))) end}, {"^mapper native db (.+)$", function(m) mm.set_native_mapper_db(m[2]) end}, {"^mapper native load$", function() local ok, err = mm.load_native_mapper_db(); if not ok then mm.warn(err) end end}, {"^mapper native load (.+)$", function(m) local ok, err = mm.load_native_mapper_db(m[2]); if not ok then mm.warn(err) end end}, {"^mapper native inspect$", function() run_inspect(mm.state.map_db) end}, {"^mapper native inspect (.+)$", function(m) run_inspect(m[2]) end}, {"^mapper native convert$", function() local ok, err = mm.import.convert_sqlite_to_mudlet(mm.state.map_db); if not ok then mm.warn(err) end end}, {"^mapper native convert (.+) to (.+)$", function(m) local ok, err = mm.import.convert_sqlite_to_mudlet(m[2], m[3]); if not ok then mm.warn(err) end end}, {"^mapper native convert (.+)$", function(m) local ok, err = mm.import.convert_sqlite_to_mudlet(m[2]); if not ok then mm.warn(err) end end}, {"^mapper hide$", function() mm.minimap.hide_all() end}, {"^mapper show$", function() mm.minimap.show_all() end}, {"^mapper (minimap|bigmap|map) (show|hide|lock|unlock)$", function(m) handle_window_command(m[2], m[3]) end}, {"^mapper (minimap|bigmap|map) move (%S+) (%S+)$", function(m) handle_window_command(m[2], "move", m[3], m[4]) end}, {"^mapper (minimap|bigmap|map) resize (%S+) (%S+)$", function(m) handle_window_command(m[2], "resize", m[3], m[4]) end}, {"^maptype (.+)$", function(m) mm.minimap.set_type(m[2]) end}, {"^mapshow (roomname|room|exits|coordinates|coordinate|coords|coord|echo) (on|off)$", function(m) mm.minimap.toggle_show(m[2], m[3]) end}, {"^resetaard$", function() mm.note("Mapper reset complete.") end}, {"^recon?$", function() send("recon") end}, }
mm.stubbed = { "mapper findpath", "mapper find", "mapper shops", "mapper train", "mapper quest", "mapper where", "mapper unmapped", "mapper notes", "mapper bookmarks", "mapper purgezone", "mapper purgeroom", "mapper clearcache", "mapper area", "mapper list", "mapper next", "mapper portals", "mapper portal", "mapper fullportal", "mapper delete portal", "mapper editportal", "mapper portalrecall", "mapper portallevel", "mapper delete note", "mapper purge portals", "mapper cexits", "mapper deletedcexits", "mapper deletecexit", "mapper restorecexit", "mapper cexit", "mapper fullcexit", "mapper cexit_wait", "mapper areas", "mapper addnote", "mapper bounceportal", "mapper bouncerecall", "mapper noportal", "mapper norecall", "mapper ignore mismatch", "mapper backup", "mapper backups", "mapper lockexit", "mapper zoom in", "mapper zoom out", }
function mm.handle_command(line) for _, spec in ipairs(mm.alias_specs) do local matches = {line:match(spec[1])} if #matches > 0 then table.insert(matches, 1, line) spec[2](matches) return true end end
if line:find("^mapper ") then for _, prefix in ipairs(mm.stubbed) do if line:find("^" .. prefix) then mm.warn("Command recognized but not yet implemented in Mudlet port: " .. line) return true end end end return false end
function mm.register_aliases() if mm._alias then return end mm._alias = tempAlias("^(mapper .+|maptype .+|mapshow .+|resetaard|recon?)$", function() local line = matches[2] if mm.handle_command(line) then return end end) end

if mm and type(mm.register_aliases)=="function" and type(mm.register_events)=="function" and mm.minimap and type(mm.minimap.init)=="function" then mm.register_aliases() mm.register_events() mm.minimap.init()
local loaded, err = mm.load_native_mapper_db() if not loaded then mm.warn("Native mapper DB was not auto-loaded: " .. tostring(err)) end
mm.note("MMapper initialized from package scripts.") else cecho("<orange_red>[MMAPPER]<reset> Package init failed: module load order problem. ") end
